def verify_password(stored_hash, provided_password):
    """Verify password against stored hash."""
    provided_hash = hashlib.sha256(provided_password.encode()).hexdigest()
    # Use constant-time comparison to prevent timing attacks
    import hmac
    return hmac.compare_digest(stored_hash, provided_hash)


@app.route('/api/login', methods=['POST'])
def login():
    """Handle login requests with secure logging."""
    request_id = generate_request_id()
    
    data = request.get_json()
    if not data:
        secure_logger.warning(
            f"LOGIN_ATTEMPT | request_id={request_id} | status=INVALID_REQUEST | "
            f"reason=missing_json_body | ip={mask_ip(request.remote_addr)}"
        )
        return jsonify({"error": "Invalid request body"}), 400

    username = data.get('username', '')
    password = data.get('password', '')
    email = data.get('email', '')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', '')

    # Validate required fields
